import "./App.css";
import { Route, Routes } from "react-router-dom";
import Home from "./home";
import Header from "./header";

function App() {
  return (
    <div className="App">
      <Routes></Routes>
      <Route path="/" Component={<Home></Home>}></Route>
      <Route path="/header" Component={<Header></Header>}></Route>
    </div>
  );
}

export default App;
